// Self-certifying generated files: the embedded forge:hash marker.
//
// Every Tier-1 (regenerated-every-run) file forge emits carries its own
// content hash inside the existing "Code generated by forge. DO NOT
// EDIT." header block:
//
//	// forge:hash=<sha256-hex>
//
// The pristine check is purely local — recompute the hash over the
// file's bytes and compare with the embedded value. No global manifest
// is consulted, so the file's provenance travels WITH the file through
// git clones, parallel work lanes, cherry-picks, and partial commits
// (the failure class that killed .forge/checksums.json for Tier-1:
// kalshi fr-9a54388f0b — a committed manifest recorded from a WIP lane
// made a green tree unable to reproduce itself).
//
// ── Hash spec (deliberate, documented) ────────────────────────────────
//
// BodyHash(content) = sha256 over content transformed as follows:
//
//  1. CRLF → LF. A git autocrlf checkout (or an editor that re-encodes
//     line endings) must not turn a pristine render into "hand-edited".
//     Forge itself always emits LF.
//  2. Every line containing "forge:hash=" is removed in its entirety,
//     including its line terminator (the hash cannot cover itself).
//     Forge emits exactly one marker line; removal is defensive against
//     duplicates.
//  3. Trailing newlines are normalized to exactly one (a non-empty body
//     always ends "\n"; an empty body stays empty). Editors and
//     formatters disagree about final newlines; the count carries no
//     content.
//
// Anything else — including trailing whitespace inside lines — is
// hashed verbatim: it IS content.
//
// ── Marker line syntax per format ─────────────────────────────────────
//
//	//  forge:hash=…   .go .ts .tsx .js .jsx .mjs .cjs .proto .alloy .kt .rs
//	#   forge:hash=…   .yaml .yml .k .kcl .sh .bash .toml .tf .py .env
//	                   .example .gitignore .dockerignore Dockerfile
//	                   Makefile CODEOWNERS
//	--  forge:hash=…   .sql
//	<!-- forge:hash=… -->   .md .markdown .html .htm
//	/*  forge:hash=… */     .css
//
// Comment-incapable formats (JSON et al.) are NOT stampable: callers
// route those few files through the scoped .forge/hashes.json fallback
// (see FileChecksums.Unstampable) — deliberately minimal so the
// exception cannot resurrect the global manifest.
//
// ── Marker placement ──────────────────────────────────────────────────
//
// Stamp inserts the marker line, in order of preference:
//
//  1. immediately after the first line containing "Code generated by
//     forge" within the first stampBannerScanLines lines (the standard
//     banner — keeps prologue-sensitive files like "use client" TSX and
//     frontmatter-led SKILL.md correct, since the banner already sits
//     after those prologues);
//  2. for .md: after the closing --- of a leading YAML frontmatter
//     block (Claude Code requires frontmatter at byte 0);
//  3. after a #! shebang line;
//  4. at the very top.
package checksums

import (
	"bytes"
	"path"
	"strings"
)

// markerKey is the searchable token of the marker line. Any line
// containing it is treated as a marker line (and excluded from the
// body hash).
const markerKey = "forge:hash="

// UnverifiedMarkerValue is the sentinel hash value the legacy-manifest
// migration stamps into files whose provenance could not be
// established (the on-disk bytes matched neither the fresh render nor
// any hash the legacy manifest recorded). It never equals a real
// sha256, so Verify always answers Modified — the stomp guard keeps
// naming the file until the user resolves it with --force (regenerate)
// or `forge disown` (keep their bytes).
const UnverifiedMarkerValue = "unverified-legacy"

// stampBannerScanLines bounds how far into a file Stamp looks for the
// generated banner. Banners sit in the first few lines; scanning the
// whole file would let a banner-quoting docstring late in a template
// relocate the marker.
const stampBannerScanLines = 30

// VerifyStatus classifies content against its embedded marker.
type VerifyStatus int

const (
	// NoMarker — no forge:hash line present. Either a brand-new path
	// forge has never written, or a user-owned (Tier-2 / disowned)
	// file: forge claims no ownership over the bytes.
	NoMarker VerifyStatus = iota
	// Pristine — embedded hash equals the recomputed body hash: an
	// unedited forge render of SOME vintage (not necessarily the
	// current template's output).
	Pristine
	// Modified — marker present but stale: the file was hand-edited
	// after forge stamped it. The Tier-1 stomp guard refuses to
	// overwrite these.
	Modified
)

// commentStyle is the per-format marker syntax.
type commentStyle struct {
	prefix string // e.g. "// ", "# ", "-- ", "<!-- "
	suffix string // e.g. "", " -->", " */"
}

// styleByExt maps a lowercased file extension (including the dot) to
// its comment style. Extend here when a new Tier-1 output format is
// added — TestStampVerifyFixedPoint's sample table should grow with it.
var styleByExt = map[string]commentStyle{
	".go":       {prefix: "// "},
	".ts":       {prefix: "// "},
	".tsx":      {prefix: "// "},
	".js":       {prefix: "// "},
	".jsx":      {prefix: "// "},
	".mjs":      {prefix: "// "},
	".cjs":      {prefix: "// "},
	".proto":    {prefix: "// "},
	".alloy":    {prefix: "// "},
	".kt":       {prefix: "// "},
	".rs":       {prefix: "// "},
	".yaml":     {prefix: "# "},
	".yml":      {prefix: "# "},
	".k":        {prefix: "# "},
	".kcl":      {prefix: "# "},
	".sh":       {prefix: "# "},
	".bash":     {prefix: "# "},
	".toml":     {prefix: "# "},
	".tf":       {prefix: "# "},
	".py":       {prefix: "# "},
	".env":      {prefix: "# "},
	".example":  {prefix: "# "}, // *.example files (e.g. config.example)
	".sql":      {prefix: "-- "},
	".md":       {prefix: "<!-- ", suffix: " -->"},
	".markdown": {prefix: "<!-- ", suffix: " -->"},
	".html":     {prefix: "<!-- ", suffix: " -->"},
	".htm":      {prefix: "<!-- ", suffix: " -->"},
	".css":      {prefix: "/* ", suffix: " */"},
}

// styleByBase maps extension-less well-known basenames.
var styleByBase = map[string]commentStyle{
	"Dockerfile":    {prefix: "# "},
	"Makefile":      {prefix: "# "},
	"CODEOWNERS":    {prefix: "# "},
	".gitignore":    {prefix: "# "},
	".dockerignore": {prefix: "# "},
	".env":          {prefix: "# "},
}

// styleFor resolves the comment style for relPath. ok=false means the
// format cannot carry comments (or is unknown) — unstampable.
func styleFor(relPath string) (commentStyle, bool) {
	base := path.Base(strings.ReplaceAll(relPath, "\\", "/"))
	if s, ok := styleByBase[base]; ok {
		return s, true
	}
	if i := strings.LastIndexByte(base, '.'); i >= 0 {
		if s, ok := styleByExt[strings.ToLower(base[i:])]; ok {
			return s, true
		}
	}
	return commentStyle{}, false
}

// Stampable reports whether relPath's format can carry an embedded
// forge:hash marker. Unstampable Tier-1 outputs go through the scoped
// .forge/hashes.json fallback instead.
func Stampable(relPath string) bool {
	_, ok := styleFor(relPath)
	return ok
}

// normalizeNewlines converts CRLF (and stray CR) to LF.
func normalizeNewlines(content []byte) []byte {
	if !bytes.ContainsRune(content, '\r') {
		return content
	}
	content = bytes.ReplaceAll(content, []byte("\r\n"), []byte("\n"))
	return bytes.ReplaceAll(content, []byte("\r"), []byte("\n"))
}

// splitLines splits content into lines, each retaining its trailing
// "\n" (except possibly the last).
func splitLines(content []byte) [][]byte {
	var lines [][]byte
	for len(content) > 0 {
		i := bytes.IndexByte(content, '\n')
		if i < 0 {
			lines = append(lines, content)
			break
		}
		lines = append(lines, content[:i+1])
		content = content[i+1:]
	}
	return lines
}

// stripMarkerLines removes every line containing markerKey from
// LF-normalized content.
func stripMarkerLines(content []byte) []byte {
	if !bytes.Contains(content, []byte(markerKey)) {
		return content
	}
	var out []byte
	for _, line := range splitLines(content) {
		if bytes.Contains(line, []byte(markerKey)) {
			continue
		}
		out = append(out, line...)
	}
	return out
}

// BodyHash computes the self-certification digest of content per the
// hash spec at the top of this file: LF-normalized, marker lines
// excluded, trailing newlines normalized to exactly one.
func BodyHash(content []byte) string {
	body := stripMarkerLines(normalizeNewlines(content))
	body = bytes.TrimRight(body, "\n")
	if len(body) > 0 {
		body = append(body, '\n')
	}
	return Hash(body)
}

// ExtractMarker returns the embedded hash value from the first marker
// line in content, and whether a marker line was found. The value is
// the token following "forge:hash=" up to whitespace or a comment
// closer.
func ExtractMarker(content []byte) (string, bool) {
	norm := normalizeNewlines(content)
	key := []byte(markerKey)
	// Scan for the FIRST occurrence whose value is a real certification
	// hash. Source and docs that merely MENTION the marker key (e.g. this
	// package's own doc comment `forge:hash=<sha256>`, or a template string
	// literal) carry a non-hash value and must not be mistaken for a
	// forge-generated file — that produced phantom "modified"/"drift"
	// findings against forge's own source.
	search := norm
	for {
		i := bytes.Index(search, key)
		if i < 0 {
			return "", false
		}
		rest := search[i+len(key):]
		end := 0
		for end < len(rest) {
			c := rest[end]
			if c == '\n' || c == ' ' || c == '\t' || c == '\r' {
				break
			}
			end++
		}
		if val := string(rest[:end]); isHashValue(val) || val == UnverifiedMarkerValue {
			// A real certification hash, or the legacy "unverified" sentinel
			// (deliberately non-hash so Verify always answers Modified).
			return val, true
		}
		search = rest // advance past this (non-hash) mention and keep looking
	}
}

// isHashValue reports whether s is a forge certification hash: a run of
// lowercase hex digits (hex.EncodeToString output). Excludes placeholders
// like `<sha256>` and empty values that appear in prose/fixtures.
func isHashValue(s string) bool {
	if len(s) < 16 {
		return false
	}
	for i := 0; i < len(s); i++ {
		if c := s[i]; (c < '0' || c > '9') && (c < 'a' || c > 'f') {
			return false
		}
	}
	return true
}

// StripMarker removes every marker line from content (preserving the
// original line endings everywhere else). Used by `forge disown` (a
// user-owned file must not advertise forge certification) and by the
// Tier-2 reclassification path.
func StripMarker(content []byte) []byte {
	if !bytes.Contains(content, []byte(markerKey)) {
		return content
	}
	// Work on raw bytes (not LF-normalized) so we only ever delete the
	// marker lines, never re-encode the user's file.
	var out []byte
	rest := content
	for len(rest) > 0 {
		i := bytes.IndexByte(rest, '\n')
		var line []byte
		if i < 0 {
			line, rest = rest, nil
		} else {
			line, rest = rest[:i+1], rest[i+1:]
		}
		if bytes.Contains(line, []byte(markerKey)) {
			continue
		}
		out = append(out, line...)
	}
	return out
}

// Verify classifies content against its embedded marker. Purely local:
// no filesystem, no manifest.
func Verify(content []byte) VerifyStatus {
	embedded, found := ExtractMarker(content)
	if !found {
		return NoMarker
	}
	if embedded == BodyHash(content) {
		return Pristine
	}
	return Modified
}

// markerLine renders the full marker line (terminated with "\n") for
// relPath's comment style and the given hash value.
func markerLine(relPath, hash string) ([]byte, bool) {
	style, ok := styleFor(relPath)
	if !ok {
		return nil, false
	}
	return []byte(style.prefix + markerKey + hash + style.suffix + "\n"), true
}

// StampWithValue inserts a marker line carrying an explicit value
// (used by the migration's UnverifiedMarkerValue sentinel). Any
// existing marker lines are removed first. Returns ok=false for
// unstampable formats.
func StampWithValue(relPath string, content []byte, value string) ([]byte, bool) {
	body := stripMarkerLines(content)
	line, ok := markerLine(relPath, value)
	if !ok {
		return nil, false
	}
	idx := markerInsertOffset(relPath, body)
	out := make([]byte, 0, len(body)+len(line))
	out = append(out, body[:idx]...)
	out = append(out, line...)
	out = append(out, body[idx:]...)
	return out, true
}

// Stamp embeds the self-certification marker into content: existing
// marker lines are removed, the body hash is computed, and the marker
// line is inserted per the placement rules. Stamping is idempotent —
// Stamp(Stamp(x)) == Stamp(x) — because the hash excludes the marker
// line. Returns ok=false for unstampable formats.
func Stamp(relPath string, content []byte) ([]byte, bool) {
	if !Stampable(relPath) {
		return nil, false
	}
	return StampWithValue(relPath, content, BodyHash(content))
}

// markerInsertOffset returns the byte offset in (marker-free) content
// where the marker line goes. See the placement rules in the package
// doc above.
func markerInsertOffset(relPath string, content []byte) int {
	lines := splitLines(content)

	// Rule 1: after the generated banner.
	offset := 0
	for n, line := range lines {
		if n >= stampBannerScanLines {
			break
		}
		if bytes.Contains(line, []byte("Code generated by forge")) {
			return offset + len(line)
		}
		offset += len(line)
	}

	// Rule 2: markdown frontmatter must stay at byte 0.
	lower := strings.ToLower(relPath)
	if strings.HasSuffix(lower, ".md") || strings.HasSuffix(lower, ".markdown") {
		if bytes.HasPrefix(content, []byte("---\n")) {
			offset = len("---\n")
			for _, line := range splitLines(content[offset:]) {
				offset += len(line)
				if bytes.Equal(bytes.TrimRight(line, "\n"), []byte("---")) {
					return offset
				}
			}
		}
	}

	// Rule 3: shebang stays on line 1.
	if bytes.HasPrefix(content, []byte("#!")) && len(lines) > 0 {
		return len(lines[0])
	}

	// Rule 4: top of file.
	return 0
}
